    _enter_idle_history() {
        const history = this._getHistory('idle_history');
        if (history.size > 0) {
            // Restore saved history
            for (const stateId of history) {
                const enterFn = this['_enter_' + stateId.replace(/-/g, '_').replace(/\./g, '_')];
                if (enterFn) enterFn.call(this);
            }
        } else {
            // No history - use default transition
        }
    }

    _enter_no_tip() {
        this._enterState('no_tip');
        if (this._traceListener) this._traceListener.onStateEnter('no_tip', [...this.activeStates], Date.now());
    }

    _exit_no_tip() {
        if (this._traceListener) this._traceListener.onStateExit('no_tip', [...this.activeStates], Date.now());
        this._exitState('no_tip');
    }

