                enabled.add('C0ZA');
                enabled.add('C0JY');
                enabled.add('C0JZ');
                enabled.add('C0KY');
                enabled.add('C0KZ');
                enabled.add('C0JP');
                enabled.add('C0JE');
                enabled.add('C0XL');
                enabled.add('C0JR');
                enabled.add('C0DC');
                enabled.add('C0RY');
